/** Validates that the {@link PipelineOptions} conforms to all the {@link Validation} criteria. */
@SuppressWarnings({
  "nullness" // TODO(https://github.com/apache/beam/issues/20497)
})
public class PipelineOptionsValidator {

  /**
   * Returns a new {@link Builder} for constructing a {@link PipelineOptionsValidator} that
   * accumulates validation rules to be run against a {@link PipelineOptions} instance.
   */
  public static Builder builder() {
    return new Builder();
  }

  /**
   * A builder that accumulates validation rules and applies them to a {@link PipelineOptions}
   * instance, returning a {@link ValidationResult} with any errors or warnings.
   */
  public static class Builder {
    private final List<ValidationRule> rules = new ArrayList<>();

    private Builder() {}

    /**
     * Adds a rule that the named option must be non-null when {@link #validate} is called.
     *
     * @param fieldName the getter-style property name (e.g. {@code "jobName"})
     * @return this builder
     */
    public Builder validateRequired(String fieldName) {
      rules.add(new RequiredRule(fieldName));
      return this;
    }

    /**
     * Adds a rule that the named option's value must be assignable to {@code expectedType} when
     * {@link #validate} is called.
     *
     * @param fieldName the getter-style property name (e.g. {@code "parallelism"})
     * @param expectedType the required type
     * @return this builder
     */
    public Builder validateType(String fieldName, Class<?> expectedType) {
      rules.add(new TypeRule(fieldName, expectedType));
      return this;
    }

    /**
     * Adds a rule that the named option's value must lie within [{@code min}, {@code max}]
     * (inclusive) when {@link #validate} is called. Both bounds are optional; pass {@code null} to
     * skip a bound.
     *
     * @param fieldName the getter-style property name
     * @param min inclusive lower bound, or {@code null} for no lower bound
     * @param max inclusive upper bound, or {@code null} for no upper bound
     * @param <C> a {@link Comparable} type
     * @return this builder
     */
    public <C extends Comparable<C>> Builder validateRange(String fieldName, C min, C max) {
      rules.add(new RangeRule<>(fieldName, min, max));
      return this;
    }

    /**
     * Runs all accumulated validation rules against {@code options} and returns a {@link
     * ValidationResult} containing any errors or warnings.
     *
     * @param options the {@link PipelineOptions} to validate
     * @return the result of validation
     */
    public ValidationResult validate(PipelineOptions options) {
      checkNotNull(options, "options must not be null");
      List<String> errors = new ArrayList<>();
      List<String> warnings = new ArrayList<>();
      for (ValidationRule rule : rules) {
        rule.apply(options, errors, warnings);
      }
      return new ValidationResult(errors, warnings);
    }
  }

  // ---------------------------------------------------------------------------
  // Internal rule types
  // ---------------------------------------------------------------------------

  private interface ValidationRule {
    void apply(PipelineOptions options, List<String> errors, List<String> warnings);
  }

  private static final class RequiredRule implements ValidationRule {
    private final String fieldName;

    RequiredRule(String fieldName) {
      this.fieldName = checkNotNull(fieldName, "fieldName");
    }

    @Override
    public void apply(PipelineOptions options, List<String> errors, List<String> warnings) {
      Object value = getOptionValue(options, fieldName);
      if (value == null) {
        errors.add("Missing required value for option '" + fieldName + "'.");
      }
    }
  }

  private static final class TypeRule implements ValidationRule {
    private final String fieldName;
    private final Class<?> expectedType;

    TypeRule(String fieldName, Class<?> expectedType) {
      this.fieldName = checkNotNull(fieldName, "fieldName");
      this.expectedType = checkNotNull(expectedType, "expectedType");
    }

    @Override
    public void apply(PipelineOptions options, List<String> errors, List<String> warnings) {
      Object value = getOptionValue(options, fieldName);
      if (value != null && !expectedType.isInstance(value)) {
        errors.add(
            "Option '"
                + fieldName
                + "' has type "
                + value.getClass().getName()
                + " but expected "
                + expectedType.getName()
                + ".");
      }
    }
  }

  private static final class RangeRule<C extends Comparable<C>> implements ValidationRule {
    private final String fieldName;
    private final C min;
    private final C max;

    RangeRule(String fieldName, C min, C max) {
      this.fieldName = checkNotNull(fieldName, "fieldName");
      this.min = min;
      this.max = max;
    }

    @Override
    @SuppressWarnings("unchecked")
    public void apply(PipelineOptions options, List<String> errors, List<String> warnings) {
      Object value = getOptionValue(options, fieldName);
      if (value == null) {
        return;
      }
      C comparable;
      try {
        comparable = (C) value;
      } catch (ClassCastException e) {
        errors.add(
            "Option '"
                + fieldName
                + "' value '"
                + value
                + "' cannot be compared for range validation.");
        return;
      }
      if (min != null && comparable.compareTo(min) < 0) {
        errors.add(
            "Option '"
                + fieldName
                + "' value '"
                + value
                + "' is less than the minimum allowed value '"
                + min
                + "'.");
      }
      if (max != null && comparable.compareTo(max) > 0) {
        errors.add(
            "Option '"
                + fieldName
                + "' value '"
                + value
                + "' is greater than the maximum allowed value '"
                + max
                + "'.");
      }
    }
  }

  /**
   * Resolves the value of the named option from {@code options} by looking for a getter method
   * whose name matches {@code "get" + capitalize(fieldName)} or exactly {@code fieldName}.
   */
  private static Object getOptionValue(PipelineOptions options, String fieldName) {
    String getterName = "get" + Character.toUpperCase(fieldName.charAt(0)) + fieldName.substring(1);
    for (Method method : options.getClass().getMethods()) {
      if ((method.getName().equals(getterName) || method.getName().equals(fieldName))
          && method.getParameterCount() == 0) {
        try {
          return method.invoke(options);
        } catch (Exception e) {
          return null;
        }
      }
    }
    return null;
  }

