    44	   */
    45	  public static Builder builder() {
    46	    return new Builder();
    47	  }
    48	
    49	  /**
    50	   * A builder that accumulates validation rules and applies them to a {@link PipelineOptions}
    51	   * instance, returning a {@link ValidationResult} with any errors or warnings.
    52	   */
    53	  public static class Builder {
    54	    private final List<ValidationRule> rules = new ArrayList<>();
    55	
    56	    private Builder() {}
    57	
    58	    /**
    59	     * Adds a rule that the named option must be non-null when {@link #validate} is called.
    60	     *
    61	     * @param fieldName the getter-style property name (e.g. {@code "jobName"})
    62	     * @return this builder
    63	     */
    64	    public Builder validateRequired(String fieldName) {
    65	      rules.add(new RequiredRule(fieldName));
    66	      return this;
    67	    }
    68	
    69	    /**
    70	     * Adds a rule that the named option's value must be assignable to {@code expectedType} when
    71	     * {@link #validate} is called.
    72	     *
    73	     * @param fieldName the getter-style property name (e.g. {@code "parallelism"})
    74	     * @param expectedType the required type
    75	     * @return this builder
    76	     */
    77	    public Builder validateType(String fieldName, Class<?> expectedType) {
    78	      rules.add(new TypeRule(fieldName, expectedType));
    79	      return this;
    80	    }
    81	
    82	    /**
    83	     * Adds a rule that the named option's value must lie within [{@code min}, {@code max}]
    84	     * (inclusive) when {@link #validate} is called. Both bounds are optional; pass {@code null} to
    85	     * skip a bound.
    86	     *
    87	     * @param fieldName the getter-style property name
    88	     * @param min inclusive lower bound, or {@code null} for no lower bound
    89	     * @param max inclusive upper bound, or {@code null} for no upper bound
    90	     * @param <C> a {@link Comparable} type
    91	     * @return this builder
    92	     */
    93	    public <C extends Comparable<C>> Builder validateRange(String fieldName, C min, C max) {
    94	      rules.add(new RangeRule<>(fieldName, min, max));
    95	      return this;
    96	    }
    97	
    98	    /**
    99	     * Runs all accumulated validation rules against {@code options} and returns a {@link
   100	     * ValidationResult} containing any errors or warnings.
   101	     *
   102	     * @param options the {@link PipelineOptions} to validate
   103	     * @return the result of validation
   104	     */
   105	    public ValidationResult validate(PipelineOptions options) {
   106	      checkNotNull(options, "options must not be null");
   107	      List<String> errors = new ArrayList<>();
   108	      List<String> warnings = new ArrayList<>();
   109	      for (ValidationRule rule : rules) {
   110	        rule.apply(options, errors, warnings);
   111	      }
   112	      return new ValidationResult(errors, warnings);
   113	    }
   114	  }
