   116	  // ---------------------------------------------------------------------------
   117	  // Internal rule types
   118	  // ---------------------------------------------------------------------------
   119	
   120	  private interface ValidationRule {
   121	    void apply(PipelineOptions options, List<String> errors, List<String> warnings);
   122	  }
   123	
   124	  private static final class RequiredRule implements ValidationRule {
   125	    private final String fieldName;
   126	
   127	    RequiredRule(String fieldName) {
   128	      this.fieldName = checkNotNull(fieldName, "fieldName");
   129	    }
   130	
   131	    @Override
   132	    public void apply(PipelineOptions options, List<String> errors, List<String> warnings) {
   133	      Object value = getOptionValue(options, fieldName);
   134	      if (value == null) {
   135	        errors.add("Missing required value for option '" + fieldName + "'.");
   136	      }
   137	    }
   138	  }
   139	
   140	  private static final class TypeRule implements ValidationRule {
   141	    private final String fieldName;
   142	    private final Class<?> expectedType;
   143	
   144	    TypeRule(String fieldName, Class<?> expectedType) {
   145	      this.fieldName = checkNotNull(fieldName, "fieldName");
   146	      this.expectedType = checkNotNull(expectedType, "expectedType");
   147	    }
   148	
   149	    @Override
   150	    public void apply(PipelineOptions options, List<String> errors, List<String> warnings) {
   151	      Object value = getOptionValue(options, fieldName);
   152	      if (value != null && !expectedType.isInstance(value)) {
   153	        errors.add(
   154	            "Option '"
   155	                + fieldName
   156	                + "' has type "
   157	                + value.getClass().getName()
   158	                + " but expected "
   159	                + expectedType.getName()
   160	                + ".");
   161	      }
   162	    }
   163	  }
   164	
   165	  private static final class RangeRule<C extends Comparable<C>> implements ValidationRule {
   166	    private final String fieldName;
   167	    private final C min;
   168	    private final C max;
   169	
   170	    RangeRule(String fieldName, C min, C max) {
   171	      this.fieldName = checkNotNull(fieldName, "fieldName");
   172	      this.min = min;
   173	      this.max = max;
   174	    }
   175	
   176	    @Override
   177	    @SuppressWarnings("unchecked")
   178	    public void apply(PipelineOptions options, List<String> errors, List<String> warnings) {
   179	      Object value = getOptionValue(options, fieldName);
   180	      if (value == null) {
   181	        return;
   182	      }
   183	      C comparable;
   184	      try {
   185	        comparable = (C) value;
   186	      } catch (ClassCastException e) {
   187	        errors.add(
   188	            "Option '"
   189	                + fieldName
   190	                + "' value '"
   191	                + value
   192	                + "' cannot be compared for range validation.");
   193	        return;
   194	      }
   195	      if (min != null && comparable.compareTo(min) < 0) {
   196	        errors.add(
   197	            "Option '"
   198	                + fieldName
   199	                + "' value '"
   200	                + value
   201	                + "' is less than the minimum allowed value '"
   202	                + min
   203	                + "'.");
   204	      }
   205	      if (max != null && comparable.compareTo(max) > 0) {
   206	        errors.add(
   207	            "Option '"
   208	                + fieldName
   209	                + "' value '"
   210	                + value
   211	                + "' is greater than the maximum allowed value '"
   212	                + max
   213	                + "'.");
   214	      }
   215	    }
   216	  }
