   218	  /**
   219	   * Resolves the value of the named option from {@code options} by looking for a getter method
   220	   * whose name matches {@code "get" + capitalize(fieldName)} or exactly {@code fieldName}.
   221	   */
   222	  private static Object getOptionValue(PipelineOptions options, String fieldName) {
   223	    String getterName = "get" + Character.toUpperCase(fieldName.charAt(0)) + fieldName.substring(1);
   224	    for (Method method : options.getClass().getMethods()) {
   225	      if ((method.getName().equals(getterName) || method.getName().equals(fieldName))
   226	          && method.getParameterCount() == 0) {
   227	        try {
   228	          return method.invoke(options);
   229	        } catch (Exception e) {
   230	          return null;
   231	        }
   232	      }
   233	    }
   234	    return null;
   235	  }
