   237	  /**
   238	   * Validates that the passed {@link PipelineOptions} conforms to all the validation criteria from
   239	   * the passed in interface.
   240	   *
   241	   * <p>Note that the interface requested must conform to the validation criteria specified on
   242	   * {@link PipelineOptions#as(Class)}.
   243	   *
   244	   * @param klass The interface to fetch validation criteria from.
   245	   * @param options The {@link PipelineOptions} to validate.
   246	   * @return Validated options.
   247	   */
   248	  public static <T extends PipelineOptions> T validate(Class<T> klass, PipelineOptions options) {
   249	    return validate(klass, options, false);
   250	  }
