   252	  /**
   253	   * Validates that the passed {@link PipelineOptions} from command line interface (CLI) conforms to
   254	   * all the validation criteria from the passed in interface.
   255	   *
   256	   * <p>Note that the interface requested must conform to the validation criteria specified on
   257	   * {@link PipelineOptions#as(Class)}.
   258	   *
   259	   * @param klass The interface to fetch validation criteria from.
   260	   * @param options The {@link PipelineOptions} to validate.
   261	   * @return Validated options.
   262	   */
   263	  public static <T extends PipelineOptions> T validateCli(Class<T> klass, PipelineOptions options) {
   264	    return validate(klass, options, true);
   265	  }
   266	
   267	  private static <T extends PipelineOptions> T validate(
   268	      Class<T> klass, PipelineOptions options, boolean isCli) {
   269	    checkNotNull(klass);
   270	    checkNotNull(options);
   271	    checkArgument(Proxy.isProxyClass(options.getClass()));
   272	    checkArgument(Proxy.getInvocationHandler(options) instanceof ProxyInvocationHandler);
   273	
   274	    // Ensure the methods for T are registered on the ProxyInvocationHandler
   275	    T asClassOptions = options.as(klass);
   276	
   277	    ProxyInvocationHandler handler =
   278	        (ProxyInvocationHandler) Proxy.getInvocationHandler(asClassOptions);
   279	
   280	    SortedSetMultimap<String, Method> requiredGroups =
   281	        TreeMultimap.create(
   282	            Ordering.natural(), PipelineOptionsFactory.MethodNameComparator.INSTANCE);
   283	    for (Method method : ReflectHelpers.getClosureOfMethodsOnInterface(klass)) {
   284	      Required requiredAnnotation = method.getAnnotation(Validation.Required.class);
   285	      if (requiredAnnotation != null) {
   286	        if (requiredAnnotation.groups().length > 0) {
   287	          for (String requiredGroup : requiredAnnotation.groups()) {
   288	            requiredGroups.put(requiredGroup, method);
   289	          }
   290	        } else {
   291	          if (isCli) {
   292	            checkArgument(
   293	                handler.invoke(asClassOptions, method, null) != null,
   294	                "Missing required value for [--%s, \"%s\"]. ",
   295	                handler.getOptionName(method),
   296	                getDescription(method));
   297	          } else {
   298	            checkArgument(
   299	                handler.invoke(asClassOptions, method, null) != null,
   300	                "Missing required value for [%s, \"%s\"]. ",
   301	                method,
   302	                getDescription(method));
   303	          }
   304	        }
   305	      }
   306	    }
   307	
   308	    for (String requiredGroup : requiredGroups.keySet()) {
   309	      if (!verifyGroup(handler, asClassOptions, requiredGroups.get(requiredGroup))) {
   310	        throw new IllegalArgumentException(
   311	            "Missing required value for group ["
   312	                + requiredGroup
   313	                + "]. At least one of the following properties "
   314	                + Collections2.transform(
   315	                    requiredGroups.get(requiredGroup), ReflectHelpers::formatMethod)
   316	                + " required. Run with --help="
   317	                + klass.getSimpleName()
   318	                + " for more information.");
   319	      }
   320	    }
   321	
   322	    return asClassOptions;
   323	  }
   324	
   325	  private static boolean verifyGroup(
   326	      ProxyInvocationHandler handler, PipelineOptions options, Collection<Method> requiredGroup) {
   327	    for (Method m : requiredGroup) {
   328	      if (handler.invoke(options, m, null) != null) {
   329	        return true;
   330	      }
   331	    }
   332	    return false;
   333	  }
   334	
   335	  private static String getDescription(Method method) {
   336	    Description description = method.getAnnotation(Description.class);
   337	    return description == null ? "" : description.value();
   338	  }
